{
  "schemaVersion": "1.0.0",
  "review": {
    "title": "The Ethical Debt: Why wasting animal data is wasting animal lives",
    "abstract": "A computational critical review of data welfare, FAIR preclinical data, the 3Rs, virtual control groups, new approach methodologies, research incentives, and governance. It argues that allowing animal-derived data to become unfindable, unusable, or unreused creates an ethical debt because the welfare cost of producing those data has already been paid.",
    "reviewType": "computational-literature-review",
    "language": "en",
    "keywords": [
      "data welfare",
      "animal welfare",
      "3Rs",
      "FAIR data",
      "virtual control groups",
      "new approach methodologies",
      "reproducible research",
      "TRUST"
    ],
    "domains": [
      "preclinical research",
      "animal welfare",
      "research data management",
      "open science"
    ],
